# ─────────────────────────────────────────────
#  내장 파비콘 (base64)
# ─────────────────────────────────────────────
_FAVICON_B64 = ""
_favicon_tmp: str = ""


def _ico_to_png_bytes(ico_bytes: bytes):
    """ICO 바이너리에서 PNG 데이터 추출 (내장 PNG 없으면 None 반환)"""
    try:
        if len(ico_bytes) < 6:
            return None
        _, ico_type, count = struct.unpack_from('<HHH', ico_bytes, 0)
        if ico_type != 1:
            return None
        for i in range(count):
            off = 6 + i * 16
            if off + 16 > len(ico_bytes):
                break
            img_size, img_offset = struct.unpack_from('<II', ico_bytes, off + 8)
            if img_offset + img_size > len(ico_bytes):
                continue
            img_data = ico_bytes[img_offset:img_offset + img_size]
            if img_data[:8] == b'\x89PNG\r\n\x1a\n':
                return img_data
    except Exception:
        pass
    return None


def _get_icon_path() -> str:
    global _favicon_tmp
    if _favicon_tmp and os.path.exists(_favicon_tmp):
        return _favicon_tmp
    ext = os.path.join(_BASE_DIR, "favicon.ico")
    if os.path.exists(ext):
        _favicon_tmp = ext
        return ext
    try:
        data = base64.b64decode(_FAVICON_B64)
        fd, tmp = tempfile.mkstemp(suffix=".ico")
        os.write(fd, data)
        os.close(fd)
        _favicon_tmp = tmp
        return tmp
    except Exception:
        return ""


