class OrderApp(tk.Tk):
    def __init__(self):
        super().__init__()
        self.title("발주 확인 프로그램  by 오마이피씨")
        self.geometry("1280x700")
        self.minsize(900, 500)

        _ico = _get_icon_path()
        if _ico:
            try: self.iconbitmap(_ico)
            except Exception: pass

        # icon_img: 자식 창(Toplevel) 및 simpledialog에 아이콘 전파
        self.icon_img = None
        try:
            ico_bytes = base64.b64decode(_FAVICON_B64)
            png_data  = _ico_to_png_bytes(ico_bytes)
            if png_data:
                _png_b64  = base64.b64encode(png_data).decode()
                self.icon_img = tk.PhotoImage(data=_png_b64)
                self.iconphoto(True, self.icon_img)
        except Exception:
            pass

        self.nas_cfg  = _load_nas_config()
        self.settings = self._load_settings()

        if self.settings.get("category_version") != CATEGORY_VERSION:
            self.settings["categories"]       = DEFAULT_CATEGORIES[:]
            self.settings["category_version"] = CATEGORY_VERSION
            self._save_settings()

        if self.settings.get("nas_id"):
            self.settings["username"] = _id_to_name(self.settings["nas_id"])
            self._save_settings()

        if not self.settings.get("nas_id"):
            if not self._show_first_run():
                self.destroy()
                return

        self.orders         = []
        self.last_etag      = ""
        self.last_modified  = ""
        self._polling       = True
        self._auth_fail_cnt = 0
        self._auth_warned   = False
        self._just_saved    = False
        self._prev_snap     = {}
        self.permissions    = dict(DEFAULT_PERMISSIONS)  # NAS 로드 전 기본값
        self._status_btns   = {}  # {"상태명": tk.Button}

        self._build_ui()
        self._load_orders()
        self._load_permissions_async()   # NAS에서 권한 로드 (백그라운드)
        self._load_employees_async()     # NAS에서 직원 목록 로드 (백그라운드)
        self._start_polling()
        self.protocol("WM_DELETE_WINDOW", self._on_close)

    def _auth(self):
        return (self.settings["nas_id"], self.settings["nas_pass"])

    def _nas_url(self):
        return self.nas_cfg.get("url", DEFAULT_NAS_URL)

    def _current_user_name(self) -> str:
        return _id_to_name(self.settings.get("nas_id", ""))

    def _load_settings(self):
        if os.path.exists(SETTINGS_FILE):
            try:
                with open(SETTINGS_FILE, "r", encoding="utf-8") as f:
                    return json.load(f)
            except Exception:
                pass
        return {}

    def _save_settings(self):
        try:
            with open(SETTINGS_FILE, "w", encoding="utf-8") as f:
                json.dump(self.settings, f, ensure_ascii=False, indent=2)
        except Exception as e:
            messagebox.showerror("설정 저장 오류",
                                 f"설정 파일을 저장하지 못했습니다:\n{e}", parent=self)

    def _show_first_run(self):
        dlg = FirstRunDialog(self)
        self.wait_window(dlg)
        if dlg.result:
            self.settings["nas_id"]   = dlg.result["nas_id"]
            self.settings["nas_pass"] = dlg.result["nas_pass"]
            self.settings["username"] = _id_to_name(dlg.result["nas_id"])
            self.settings.setdefault("categories", DEFAULT_CATEGORIES[:])
            self._save_settings()
            return True
        return False

