# ─────────────────────────────────────────────
#  발주 세부 정보 다이얼로그 (더블클릭 – 읽기 전용)
#  메모 누적 추가 방식 (행별 개별 삭제)
# ─────────────────────────────────────────────
class DetailDialog(tk.Toplevel):
    def __init__(self, parent, order, categories, on_save):
        super().__init__(parent)
        self._parent  = parent
        try:
            self.iconphoto(False, parent.icon_img)
        except Exception:
            pass
        self.title("발주 상세 정보")
        self.resizable(False, True)
        self.grab_set()
        self._on_save = on_save

        _ico = _get_icon_path()
        if _ico:
            try: self.iconbitmap(_ico)
            except Exception: pass

        # 기존 메모 파싱 (문자열 → 리스트 하위 호환)
        self._memos = self._parse_memos(order.get("memo", ""))

        f = tk.Frame(self, padx=22, pady=14)
        f.pack(fill="both", expand=True)
        f.columnconfigure(1, weight=1)

        def _lbl_cell(row, text):
            tk.Label(f, text=text, font=("맑은 고딕", 9),
                     anchor="e", width=14, fg="#555"
                     ).grid(row=row, column=0, sticky="e", pady=4, padx=(0, 8))

        def _val_cell(row, text, fg="#222", wraplength=0):
            kw = {}
            if wraplength:
                kw["wraplength"] = wraplength
                kw["justify"] = "left"
            tk.Label(f, text=text, font=("맑은 고딕", 9), fg=fg,
                     anchor="w", **kw
                     ).grid(row=row, column=1, sticky="w", pady=4)

        # ── 읽기 전용 정보 ──────────────────────
        status = order.get("status", "")
        rows_data = [
            ("카테고리 :", order.get("category", "—"), "#222"),
            ("품목명 :",   order.get("item", "—"),     "#222"),
            ("수량 :",     str(order.get("qty", "—")), "#222"),
            ("상태 :",     status,                      STATUS_TEXT_COLORS.get(status, "#000")),
            ("등록자 :",   order.get("created_by","—"), "#333"),
        ]
        if order.get("ordered_by", ""):
            rows_data.append(("발주자 :", order["ordered_by"], "#1565C0"))
        for i, (lbl_t, val_t, fg) in enumerate(rows_data):
            _lbl_cell(i, lbl_t)
            _val_cell(i, val_t, fg=fg, wraplength=(280 if lbl_t == "품목명 :" else 0))

        r = len(rows_data)

        # ── 구분선 ─────────────────────────────
        ttk.Separator(f, orient="horizontal").grid(
            row=r, column=0, columnspan=2, sticky="ew", pady=(8, 4))
        r += 1

        # ── 타임스탬프 ─────────────────────────
        ts_rows = [("발주 시간 :", order.get("created_at", "—"))]
        if order.get("ordered_at", ""):
            ts_rows.append(("발주완료 시간 :", order["ordered_at"]))
        if order.get("received_at", ""):
            ts_rows.append(("입고완료 시간 :", order["received_at"]))

        for i2, (lbl_t, val_t) in enumerate(ts_rows):
            _lbl_cell(r + i2, lbl_t)
            _val_cell(r + i2, val_t, fg="#444")
        r += len(ts_rows)

        # ── 구분선 ─────────────────────────────
        ttk.Separator(f, orient="horizontal").grid(
            row=r, column=0, columnspan=2, sticky="ew", pady=(8, 4))
        r += 1

        # ── 메모 입력 ──────────────────────────
        tk.Label(f, text="메모 입력 :", font=("맑은 고딕", 9),
                 anchor="ne", width=14, fg="#555"
                 ).grid(row=r, column=0, sticky="ne", pady=6, padx=(0, 8))
        self._memo_text = tk.Text(f, height=3, width=30,
                                   font=("맑은 고딕", 9), wrap=tk.WORD,
                                   relief=tk.SUNKEN, bd=1)
        self._memo_text.grid(row=r, column=1, sticky="ew", pady=6)
        r += 1

        # ── 저장된 메모 목록 ───────────────────
        self._memo_list_frame = tk.Frame(f)
        self._memo_list_frame.grid(row=r, column=0, columnspan=2,
                                    sticky="ew", pady=(0, 6))
        self._memo_list_frame.columnconfigure(0, weight=1)
        self._refresh_memo_display()

        # ── 버튼 ───────────────────────────────
        bf = tk.Frame(self)
        bf.pack(pady=(4, 14))
        tk.Button(bf, text="메모 저장", command=self._confirm,
                  bg="#1976D2", fg="white", font=("맑은 고딕", 10),
                  width=9, pady=5, cursor="hand2").pack(side=tk.LEFT, padx=8)
        tk.Button(bf, text="닫기", command=self.destroy,
                  font=("맑은 고딕", 10), width=9, pady=5).pack(side=tk.LEFT, padx=8)
        self.bind("<Escape>", lambda e: self.destroy())
        self._center()

    def _parse_memos(self, memo_val):
        """기존 메모(문자열 또는 리스트) → list of dict 하위 호환"""
        if isinstance(memo_val, list):
            return list(memo_val)
        if isinstance(memo_val, str) and memo_val.strip():
            return [{"user": "", "text": memo_val.strip(), "time": ""}]
        return []

    def _refresh_memo_display(self):
        """저장된 메모 목록 다시 그리기"""
        for w in self._memo_list_frame.winfo_children():
            w.destroy()
        for i, m in enumerate(self._memos):
            user = m.get("user", "")
            text = m.get("text", "")
            display = f"[{user}]  {text}" if user else text

            row_f = tk.Frame(self._memo_list_frame, bg="#EEF2FF",
                             bd=1, relief=tk.GROOVE)
            row_f.grid(row=i, column=0, sticky="ew", pady=2)
            row_f.columnconfigure(0, weight=1)

            tk.Label(row_f, text=display, font=("맑은 고딕", 9),
                     fg="#1565C0", bg="#EEF2FF", anchor="w",
                     wraplength=260, justify="left"
                     ).grid(row=0, column=0, sticky="w", padx=8, pady=4)
            tk.Button(row_f, text="메모 삭제", font=("맑은 고딕", 7),
                      bg="#B71C1C", fg="white", padx=6, pady=2,
                      cursor="hand2",
                      command=lambda idx=i: self._delete_single_memo(idx)
                      ).grid(row=0, column=1, padx=6, pady=4)

    def _confirm(self):
        raw = self._memo_text.get("1.0", tk.END).strip()
        if not raw:
            return
        try:
            user_name = self._parent._current_user_name()
        except Exception:
            user_name = "알 수 없음"
        self._memos.append({
            "user": user_name,
            "text": raw,
            "time": datetime.now().strftime("%Y-%m-%d %H:%M"),
        })
        self._save_memos()
        self._memo_text.delete("1.0", tk.END)
        self._refresh_memo_display()
        self._center()

    def _delete_single_memo(self, index):
        if not messagebox.askyesno("메모 삭제", "이 메모를 삭제하시겠습니까?", parent=self):
            return
        del self._memos[index]
        self._save_memos()
        self._refresh_memo_display()
        self._center()

    def _save_memos(self):
        if self._on_save:
            self._on_save({"memo": self._memos})

    def _center(self):
        self.update_idletasks()
        x = self.master.winfo_x() + (self.master.winfo_width()  - self.winfo_width())  // 2
        y = self.master.winfo_y() + (self.master.winfo_height() - self.winfo_height()) // 2
        self.geometry(f"+{x}+{y}")


# ─────────────────────────────────────────────
#  직원 관리 다이얼로그 (관리자 전용)
# ─────────────────────────────────────────────
class EmployeeDialog(tk.Toplevel):
    """NAS ID / 이름 / 직급 등록 → USER_MAP 동적 관리"""

    def __init__(self, parent):
        super().__init__(parent)
        self._parent = parent
        try:
            self.iconphoto(False, parent.icon_img)
        except Exception:
            pass
        _ico = _get_icon_path()
        if _ico:
            try: self.iconbitmap(_ico)
            except Exception: pass
        self.title("직원 관리  (관리자 전용)")
        self.resizable(False, True)
        self.grab_set()

        # 현재 USER_MAP → 편집용 리스트 [{id, name, rank}, ...]
        self._emps = []
        for nas_id, display in USER_MAP.items():
            parts = display.rsplit(" ", 1)
            name = parts[0] if len(parts) >= 2 else display
            rank = parts[1] if len(parts) >= 2 else ""
            self._emps.append({"id": nas_id, "name": name, "rank": rank})

        self._build_ui()
        self._center()

    def _build_ui(self):
        # ── 입력 영역 ──────────────────────────
        inp = tk.LabelFrame(self, text=" 직원 추가 ", font=("맑은 고딕", 9, "bold"),
                            padx=10, pady=8)
        inp.pack(fill=tk.X, padx=12, pady=(10, 4))

        fields = [("NAS ID :", 14), ("이름 :", 8), ("직급 :", 8)]
        self._id_var   = tk.StringVar()
        self._name_var = tk.StringVar()
        self._rank_var = tk.StringVar()
        vars_ = [self._id_var, self._name_var, self._rank_var]

        for col, ((lbl, w), var) in enumerate(zip(fields, vars_)):
            tk.Label(inp, text=lbl, font=("맑은 고딕", 9)).grid(
                row=0, column=col*2, sticky="e", padx=(8 if col else 0, 2))
            tk.Entry(inp, textvariable=var, width=w,
                     font=("맑은 고딕", 9)).grid(row=0, column=col*2+1, padx=(0, 8))

        tk.Button(inp, text="＋ 추가", font=("맑은 고딕", 9),
                  bg="#1565C0", fg="white", padx=8, pady=2,
                  command=self._add_emp).grid(row=0, column=6, padx=(4, 0))

        # ── 직원 목록 ──────────────────────────
        lf = tk.LabelFrame(self, text=" 등록된 직원 목록 ", font=("맑은 고딕", 9, "bold"),
                           padx=6, pady=6)
        lf.pack(fill=tk.BOTH, expand=True, padx=12, pady=4)

        # 헤더
        hdr = tk.Frame(lf, bg="#CFD8DC")
        hdr.pack(fill=tk.X)
        for txt, w in [("NAS ID", 14), ("이름", 8), ("직급", 6), ("", 5)]:
            tk.Label(hdr, text=txt, font=("맑은 고딕", 8, "bold"),
                     bg="#CFD8DC", width=w, anchor="w"
                     ).pack(side=tk.LEFT, padx=4, pady=2)

        # 스크롤 목록
        scroll_f = tk.Frame(lf)
        scroll_f.pack(fill=tk.BOTH, expand=True)
        vsb = ttk.Scrollbar(scroll_f, orient=tk.VERTICAL)
        self._canvas = tk.Canvas(scroll_f, yscrollcommand=vsb.set,
                                  bg="white", highlightthickness=0, height=260)
        vsb.config(command=self._canvas.yview)
        self._canvas.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        vsb.pack(side=tk.LEFT, fill=tk.Y)
        self._list_frame = tk.Frame(self._canvas, bg="white")
        self._canvas_win = self._canvas.create_window(
            (0, 0), window=self._list_frame, anchor="nw")
        self._list_frame.bind("<Configure>",
            lambda e: self._canvas.configure(
                scrollregion=self._canvas.bbox("all")))
        self._canvas.bind("<Configure>",
            lambda e: self._canvas.itemconfig(self._canvas_win, width=e.width))

        # 마우스 휠 스크롤
        def _on_wheel(e):
            self._canvas.yview_scroll(-1 * (e.delta // 120), "units")
        self._canvas.bind("<MouseWheel>", _on_wheel)
        self._list_frame.bind("<MouseWheel>", _on_wheel)
        self._on_wheel = _on_wheel   # _refresh_list에서 자식 위젯에 바인딩용

        self._refresh_list()

        # ── 하단 버튼 ──────────────────────────
        bf = tk.Frame(self, bg="#ECEFF1", bd=1, relief=tk.GROOVE)
        bf.pack(fill=tk.X, side=tk.BOTTOM, padx=4, pady=(0, 4))
        tk.Label(bf, text="※ NAS에 저장 후 모든 PC에 즉시 반영됩니다.",
                 font=("맑은 고딕", 7), fg="#90A4AE", bg="#ECEFF1"
                 ).pack(side=tk.LEFT, padx=10, pady=4)
        tk.Button(bf, text="닫기", font=("맑은 고딕", 10),
                  command=self.destroy, padx=12, pady=3
                  ).pack(side=tk.RIGHT, padx=6, pady=4)
        tk.Button(bf, text="💾  저장", font=("맑은 고딕", 10, "bold"),
                  command=self._save, bg="#1565C0", fg="white",
                  padx=16, pady=3).pack(side=tk.RIGHT, padx=4, pady=4)

    def _refresh_list(self):
        for w in self._list_frame.winfo_children():
            w.destroy()
        bg_cycle = ["white", "#F5F5F5"]
        for i, emp in enumerate(self._emps):
            bg = bg_cycle[i % 2]
            row = tk.Frame(self._list_frame, bg=bg)
            row.pack(fill=tk.X)
            for val, w in [(emp["id"], 14), (emp["name"], 8), (emp["rank"], 6)]:
                lbl = tk.Label(row, text=val, font=("맑은 고딕", 9),
                               bg=bg, width=w, anchor="w")
                lbl.pack(side=tk.LEFT, padx=4, pady=3)
                lbl.bind("<MouseWheel>", self._on_wheel)
            tk.Button(row, text="삭제", font=("맑은 고딕", 7),
                      bg="#B71C1C", fg="white", padx=4, pady=1,
                      cursor="hand2",
                      command=lambda idx=i: self._del_emp(idx)
                      ).pack(side=tk.LEFT, padx=4)
            row.bind("<MouseWheel>", self._on_wheel)

    def _add_emp(self):
        nas_id = self._id_var.get().strip()
        name   = self._name_var.get().strip()
        rank   = self._rank_var.get().strip()
        if not nas_id or not name:
            messagebox.showwarning("입력 오류", "NAS ID와 이름은 필수입니다.", parent=self)
            return
        # 중복 체크
        if any(e["id"] == nas_id for e in self._emps):
            messagebox.showwarning("중복", f"'{nas_id}' ID가 이미 등록되어 있습니다.", parent=self)
            return
        self._emps.append({"id": nas_id, "name": name, "rank": rank})
        self._id_var.set(""); self._name_var.set(""); self._rank_var.set("")
        self._refresh_list()

    def _del_emp(self, index):
        emp = self._emps[index]
        if not messagebox.askyesno("삭제 확인",
                f"'{emp['name']} {emp['rank']}' ({emp['id']}) 직원을 삭제하시겠습니까?",
                parent=self):
            return
        del self._emps[index]
        self._refresh_list()

    def _save(self):
        # NAS에 PUT
        data = json.dumps(self._emps, ensure_ascii=False, indent=2).encode("utf-8")
        saved_ok = False
        try:
            r = requests.put(self._parent._employees_url(),
                             auth=self._parent._auth(), data=data,
                             headers={"Content-Type": "application/json; charset=utf-8"},
                             verify=False, timeout=10)
            saved_ok = r.status_code in (200, 201, 204)
        except Exception:
            pass

        # USER_MAP 즉시 반영
        new_map = {e["id"]: f"{e['name']} {e['rank']}".strip()
                   for e in self._emps if e.get("id")}
        USER_MAP.clear()
        USER_MAP.update(new_map)

        if saved_ok:
            messagebox.showinfo("저장 완료", "직원 목록이 NAS에 저장되었습니다.", parent=self)
        else:
            messagebox.showwarning("저장 실패",
                "NAS 저장 실패 — 앱 내에서는 임시 적용됨\n(재시작 시 초기화될 수 있습니다)",
                parent=self)

    def _center(self):
        self.update_idletasks()
        x = self.master.winfo_x() + (self.master.winfo_width()  - self.winfo_width())  // 2
        y = self.master.winfo_y() + (self.master.winfo_height() - self.winfo_height()) // 2
        self.geometry(f"+{x}+{y}")


# ─────────────────────────────────────────────
#  메모 목록 다이얼로그
# ─────────────────────────────────────────────
class MemoListDialog(tk.Toplevel):
    """메모가 있는 발주 목록 표시 – 더블클릭 시 상세 정보 팝업"""

    def __init__(self, parent, orders_with_memo):
        super().__init__(parent)
        self._parent = parent
        self._orders = orders_with_memo
        try:
            self.iconphoto(False, parent.icon_img)
        except Exception:
            pass
        _ico = _get_icon_path()
        if _ico:
            try: self.iconbitmap(_ico)
            except Exception: pass
        self.title("메모 목록")
        self.resizable(False, True)
        self.grab_set()

        # 안내
        tk.Label(self, text="메모가 있는 항목 목록 (더블클릭 → 상세 정보)",
                 font=("맑은 고딕", 8), fg="#546E7A"
                 ).pack(fill=tk.X, padx=10, pady=(8, 2))

        # 리스트박스
        fr = tk.Frame(self)
        fr.pack(fill=tk.BOTH, expand=True, padx=10, pady=4)
        vsb = ttk.Scrollbar(fr, orient=tk.VERTICAL)
        self._lb = tk.Listbox(fr, font=("맑은 고딕", 10),
                               yscrollcommand=vsb.set,
                               width=40, height=min(len(orders_with_memo) + 1, 15),
                               selectmode=tk.SINGLE, activestyle="none",
                               exportselection=False)
        vsb.config(command=self._lb.yview)
        self._lb.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        vsb.pack(side=tk.LEFT, fill=tk.Y)

        for o in orders_with_memo:
            item_name = o.get("item", "—")
            self._lb.insert(tk.END, f"  {item_name}")

        self._lb.bind("<Double-Button-1>", self._on_double_click)

        # 닫기 버튼
        tk.Button(self, text="닫기", command=self.destroy,
                  font=("맑은 고딕", 10), width=8, pady=4
                  ).pack(pady=(2, 10))

        self.bind("<Escape>", lambda e: self.destroy())
        self._center()

    def _on_double_click(self, event):
        sel = self._lb.curselection()
        if not sel:
            return
        order = self._orders[sel[0]]

        def on_save(result):
            idx = next((i for i, o in enumerate(self._parent.orders)
                        if o["id"] == order["id"]), None)
            if idx is not None:
                self._parent.orders[idx]["memo"] = result["memo"]
                if self._parent._save_orders():
                    self._parent._apply_filter()

        DetailDialog(self._parent, order,
                     self._parent.settings.get("categories", DEFAULT_CATEGORIES),
                     on_save=on_save)

    def _center(self):
        self.update_idletasks()
        x = self.master.winfo_x() + (self.master.winfo_width()  - self.winfo_width())  // 2
        y = self.master.winfo_y() + (self.master.winfo_height() - self.winfo_height()) // 2
        self.geometry(f"+{x}+{y}")


# ─────────────────────────────────────────────
#  권한 할당 다이얼로그
# ─────────────────────────────────────────────
class PermissionDialog(tk.Toplevel):
    """각 상태 변경 버튼에 대한 사용자 권한 할당 (관리자 전용)"""

    def __init__(self, parent):
        super().__init__(parent)
        self._parent = parent
        try:
            self.iconphoto(False, parent.icon_img)
        except Exception:
            pass
        _ico = _get_icon_path()
        if _ico:
            try: self.iconbitmap(_ico)
            except Exception: pass
        self.title("권한 할당  (관리자 전용)")
        self.resizable(False, False)
        self.grab_set()

        # 현재 권한 복사본
        self._perms = {s: list(parent.permissions.get(s, []))
                       for s in STATUS_LIST}
        # 체크박스 변수: {상태: {nas_id: BooleanVar}}
        self._vars  = {}

        self._build_ui()
        self._center()

    def _build_ui(self):
        tk.Label(self,
                 text="각 상태 변경 버튼에 대한 사용자 권한을 설정합니다.\n"
                      "체크가 없으면 모든 사용자 허용, 체크하면 선택된 사람만 가능.",
                 font=("맑은 고딕", 8), fg="#546E7A", justify="left"
                 ).pack(fill=tk.X, padx=12, pady=(8, 4))

        main = tk.Frame(self, padx=8, pady=4)
        main.pack(fill=tk.BOTH, expand=True)

        # 상태별 LabelFrame
        statuses_show = ["발주완료", "입고완료", "반품 요청", "반품 완료", "취소"]
        for col, status in enumerate(statuses_show):
            lf = tk.LabelFrame(main, text=f" {status} ",
                               font=("맑은 고딕", 9, "bold"),
                               bg=STATUS_COLORS.get(status, "#FFF"),
                               padx=6, pady=6)
            lf.grid(row=0, column=col, padx=4, pady=4, sticky="ns")

            self._vars[status] = {}
            for nas_id, name in USER_MAP.items():
                var = tk.BooleanVar(value=(nas_id in self._perms.get(status, [])))
                self._vars[status][nas_id] = var
                tk.Checkbutton(lf, text=name,
                               variable=var,
                               font=("맑은 고딕", 9),
                               bg=STATUS_COLORS.get(status, "#FFF"),
                               anchor="w"
                               ).pack(fill=tk.X, pady=1)

        # 하단 버튼
        bf = tk.Frame(self, bg="#ECEFF1", bd=1, relief=tk.GROOVE)
        bf.pack(fill=tk.X, side=tk.BOTTOM, padx=4, pady=(0, 4))
        tk.Label(bf, text="※ 체크 없음 = 전체 허용 / NAS 저장 후 즉시 적용",
                 font=("맑은 고딕", 7), fg="#90A4AE", bg="#ECEFF1"
                 ).pack(side=tk.LEFT, padx=10, pady=4)
        tk.Button(bf, text="닫기", font=("맑은 고딕", 10),
                  command=self.destroy, padx=12, pady=3
                  ).pack(side=tk.RIGHT, padx=6, pady=4)
        tk.Button(bf, text="💾  저장", font=("맑은 고딕", 10, "bold"),
                  command=self._save, bg="#1565C0", fg="white",
                  padx=16, pady=3).pack(side=tk.RIGHT, padx=4, pady=4)

    def _save(self):
        new_perms = {}
        for status, id_vars in self._vars.items():
            checked = [nid for nid, var in id_vars.items() if var.get()]
            new_perms[status] = checked
        # "대기중" 은 항상 전체 허용
        new_perms["대기중"] = []

        # NAS에 저장
        saved_ok = False
        try:
            url  = self._parent._permissions_url()
            data = json.dumps(new_perms, ensure_ascii=False, indent=2).encode("utf-8")
            r = requests.put(url, auth=self._parent._auth(), data=data,
                             headers={"Content-Type": "application/json; charset=utf-8"},
                             verify=False, timeout=10)
            saved_ok = r.status_code in (200, 201, 204)
        except Exception:
            pass

        # 앱에 즉시 반영
        self._parent.permissions = new_perms
        self._parent._update_perm_buttons()

        if saved_ok:
            messagebox.showinfo("저장 완료", "권한 설정이 NAS에 저장되었습니다.", parent=self)
        else:
            messagebox.showwarning("저장 실패",
                "NAS 저장 실패 — 앱 내에서는 임시 적용됨\n(재시작 시 초기화될 수 있습니다)",
                parent=self)

    def _center(self):
        self.update_idletasks()
        x = self.master.winfo_x() + (self.master.winfo_width()  - self.winfo_width())  // 2
        y = self.master.winfo_y() + (self.master.winfo_height() - self.winfo_height()) // 2
        self.geometry(f"+{x}+{y}")


# ─────────────────────────────────────────────
#  카테고리 관리 다이얼로그
# ─────────────────────────────────────────────
class CategoryDialog(tk.Toplevel):
    def __init__(self, parent, categories):
        super().__init__(parent)
        try:
            self.iconphoto(False, parent.icon_img)
        except Exception:
            pass
        _ico = _get_icon_path()
        if _ico:
            try: self.iconbitmap(_ico)
            except Exception: pass
        self.title("카테고리 관리")
        self.resizable(False, False)
        self.grab_set()
        self.result = None

        tk.Label(self, text="카테고리 목록",
                 font=("맑은 고딕", 10, "bold")).pack(pady=(14, 4))

        lf = tk.Frame(self)
        lf.pack(padx=16, pady=4)
        self.listbox = tk.Listbox(lf, width=26, height=14,
                                   font=("맑은 고딕", 10), selectmode=tk.SINGLE)
        self.listbox.pack(side=tk.LEFT)
        vsb = ttk.Scrollbar(lf, command=self.listbox.yview)
        vsb.pack(side=tk.LEFT, fill=tk.Y)
        self.listbox.config(yscrollcommand=vsb.set)
        for cat in categories:
            self.listbox.insert(tk.END, cat)

        af = tk.Frame(self)
        af.pack(pady=4)
        self.new_var = tk.StringVar()
        tk.Entry(af, textvariable=self.new_var, width=16,
                 font=("맑은 고딕", 10)).pack(side=tk.LEFT, padx=4)
        tk.Button(af, text="추가", command=self._add,  padx=6).pack(side=tk.LEFT, padx=2)
        tk.Button(af, text="삭제", command=self._del,  padx=6).pack(side=tk.LEFT, padx=2)
        tk.Button(af, text="↑",   command=self._up,   padx=4).pack(side=tk.LEFT, padx=2)
        tk.Button(af, text="↓",   command=self._down, padx=4).pack(side=tk.LEFT, padx=2)

        bf = tk.Frame(self)
        bf.pack(pady=(6, 14))
        tk.Button(bf, text="저장", command=self._save,
                  bg="#1976D2", fg="white", font=("맑은 고딕", 10),
                  width=8, pady=4, cursor="hand2").pack(side=tk.LEFT, padx=8)
        tk.Button(bf, text="취소", command=self.destroy,
                  font=("맑은 고딕", 10), width=8, pady=4).pack(side=tk.LEFT, padx=8)
        self._center()

    def _add(self):
        name = self.new_var.get().strip()
        if name and name not in self.listbox.get(0, tk.END):
            self.listbox.insert(tk.END, name)
            self.new_var.set("")

    def _del(self):
        sel = self.listbox.curselection()
        if sel: self.listbox.delete(sel[0])

    def _up(self):
        sel = self.listbox.curselection()
        if sel and sel[0] > 0:
            i = sel[0]; val = self.listbox.get(i)
            self.listbox.delete(i); self.listbox.insert(i - 1, val)
            self.listbox.select_set(i - 1)

    def _down(self):
        sel = self.listbox.curselection()
        if sel and sel[0] < self.listbox.size() - 1:
            i = sel[0]; val = self.listbox.get(i)
            self.listbox.delete(i); self.listbox.insert(i + 1, val)
            self.listbox.select_set(i + 1)

    def _save(self):
        self.result = list(self.listbox.get(0, tk.END))
        self.destroy()

    def _center(self):
        self.update_idletasks()
        x = self.master.winfo_x() + (self.master.winfo_width()  - self.winfo_width())  // 2
        y = self.master.winfo_y() + (self.master.winfo_height() - self.winfo_height()) // 2
        self.geometry(f"+{x}+{y}")


